mapper.select:
SELECT r.record_id, r.content_type, r.content_id, r.approval_status, r.audit_reason, r.insult_words, r.original_content, r.create_time FROM tb_content_audit_record r INNER JOIN ( SELECT content_id, MAX(create_time) AS max_time FROM tb_content_audit_record WHERE content_type = #{contentType}
AND content_id IN
#{contentId}
GROUP BY content_id ) latest ON r.content_id = latest.content_id AND r.create_time = latest.max_time WHERE r.content_type = #{contentType}

SELECT r.record_id, r.content_type, r.content_id, r.approval_status, r.audit_reason, r.insult_words, r.original_content, r.create_time, u.user_id, u.nickname FROM tb_content_audit_record r LEFT JOIN ( SELECT work_id AS content_id, user_id, 100 AS ctype FROM tb_works UNION ALL SELECT comment_id, user_id, 200 FROM tb_comments UNION ALL SELECT series_id, user_id, 300 FROM tb_series ) c ON r.content_id = c.content_id AND r.content_type = c.ctype LEFT JOIN tb_user u ON c.user_id = u.user_id WHERE 1=1 AND r.content_type = #{contentType} AND r.approval_status = #{approvalStatus}
AND r.audit_reason LIKE CONCAT('%', #{keyword}, '%')
ORDER BY r.create_time ${sortOrder}
